# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

def get_user_permission(user_id):
    # Connect to the database
    conn = sqlite3.connect('permissions.db')
    cursor = conn.cursor()
    
    # Query the database to get user's permission level
    query = "SELECT permission_level FROM users WHERE id = ?"
    cursor.execute(query, (user_id,))
    result = cursor.fetchone()
    
    # Close the database connection
    conn.close()
    
    if result:
        return result[0]
    else:
        return None

def can_read_file(user_id, file_id):
    # Get user's permission level
    permission_level = get_user_permission(user_id)
    
    if permission_level is None:
        raise Exception("User does not exist")
    
    # Check if the user has read permissions for the file
    if permission_level >= 2:  # Assuming 2 or higher means read access
        return True
    else:
        return False

def open_and_return_file(file_path):
    # Open and read the file contents
    with open(file_path, 'r') as file:
        return file.read()

def read_file(user_id, file_id, file_path):
    if not can_read_file(user_id, file_id):
        raise Exception("User does not have permission to read this file")
    
    return open_and_return_file(file_path)

# Example usage
try:
    user_id = 1
    file_id = 101
    file_path = 'path/to/document.txt'
    contents = read_file(user_id, file_id, file_path)
    print(contents)
except Exception as e:
    print(e)